logic [2:0] idx;
logic [7:0] vec [0:7];
logic [7:0] out;
always_ff @(posedge clk or posedge arst)
  if (arst) idx <= 3'b0;
  else      idx <= idx + 1;
assign out = vec[idx];

logic [1:0] sel;
logic [3:0] data [0:3];
logic [3:0] result;
always_ff @(posedge clk)
  if (srst) sel <= 2'b0;
  else      sel <= sel + 1;
assign result = data[sel];

logic [7:0] mem [0:15];
logic [3:0] addr;
logic [7:0] rdata;
always_ff @(posedge clk)
  rdata <= mem[addr];
